+    fn diamond() -> DiGraph {
+        //   0
+        //  / \
+        // 1   2
+        //  \ /
+        //   3
+        DiGraph::from_edges(4, &[(0, 1), (0, 2), (1, 3), (2, 3)])
+    }
+
+    fn linear() -> DiGraph {
+        // 0 -> 1 -> 2 -> 3
+        DiGraph::from_edges(4, &[(0, 1), (1, 2), (2, 3)])
+    }
+
+    fn cycle3() -> DiGraph {
+        // 0 -> 1 -> 2 -> 0
+        DiGraph::from_edges(3, &[(0, 1), (1, 2), (2, 0)])
